// src/pages/moderatordashboard.js
import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

const ModeratorDashboard = () => {
  const [users, setUsers] = useState([]);
  const [error, setError] = useState('');
  const [editingUser, setEditingUser] = useState(null);
  const [editData, setEditData] = useState({});
  const [showForm, setShowForm] = useState(false);
  const [newUser, setNewUser] = useState({
    username: '',
    email: '',
    password: '',
    role: 'student',
  });

  const navigate = useNavigate();
  const token = localStorage.getItem('accessToken');

  useEffect(() => {
    if (!token) {
      setError('No token found. Please log in again.');
      navigate('/login');
      return;
    }

    fetch('http://localhost:8000/api/manage-users/', {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    })
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) {
          setUsers(data);
        } else {
          setError('Invalid response format');
        }
      })
      .catch(() => setError('Failed to load users.'));
  }, [navigate, token]);

  const deleteUser = (id) => {
    fetch(`http://localhost:8000/api/manage-users/${id}/`, {
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    }).then(() => {
      setUsers(users.filter(user => user.id !== id));
    });
  };

  const startEdit = (user) => {
    setEditingUser(user.id);
    setEditData({ username: user.username, role: user.role, email: user.email });
  };

  const handleEditChange = (e) => {
    setEditData({ ...editData, [e.target.name]: e.target.value });
  };

  const submitEdit = (e) => {
    e.preventDefault();
    fetch(`http://localhost:8000/api/manage-users/${editingUser}/`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(editData)
    })
      .then(res => res.json())
      .then(updated => {
        setUsers(users.map(user => user.id === editingUser ? updated : user));
        setEditingUser(null);
      })
      .catch(() => setError('Update failed'));
  };

  const handleNewUserChange = (e) => {
    setNewUser({ ...newUser, [e.target.name]: e.target.value });
  };

  const createUser = (e) => {
    e.preventDefault();
    fetch('http://localhost:8000/api/register/', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${token}`
      },
      body: JSON.stringify(newUser)
    })
      .then(res => res.json())
      .then(data => {
        if (data.final_username) {
          setUsers([...users, { ...newUser, username: data.final_username }]);
          setNewUser({ username: '', email: '', password: '', role: 'student' });
          setShowForm(false);
        } else {
          setError(data.error || 'Creation failed');
        }
      })
      .catch(() => setError('Creation failed'));
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Moderator Dashboard</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}

      <button onClick={() => setShowForm(!showForm)}>
        {showForm ? 'Cancel' : 'Create New User'}
      </button>

      {showForm && (
        <form onSubmit={createUser} style={{ marginTop: '1rem', marginBottom: '2rem' }}>
          <input type="text" name="username" placeholder="Username" value={newUser.username} onChange={handleNewUserChange} required />
          <input type="email" name="email" placeholder="Email" value={newUser.email} onChange={handleNewUserChange} required />
          <input type="password" name="password" placeholder="Password" value={newUser.password} onChange={handleNewUserChange} required />
          <select name="role" value={newUser.role} onChange={handleNewUserChange}>
            <option value="student">Student</option>
            <option value="teacher">Teacher</option>
            <option value="moderator">Moderator</option>
          </select>
          <button type="submit">Submit</button>
        </form>
      )}

      <table border="1" cellPadding="8" style={{ width: '100%' }}>
        <thead>
          <tr>
            <th>ID</th><th>Username</th><th>Email</th><th>Role</th><th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map(user => (
            editingUser === user.id ? (
              <tr key={user.id}>
                <td>{user.id}</td>
                <td><input type="text" name="username" value={editData.username} onChange={handleEditChange} /></td>
                <td><input type="email" name="email" value={editData.email} onChange={handleEditChange} /></td>
                <td>
                  <select name="role" value={editData.role} onChange={handleEditChange}>
                    <option value="student">Student</option>
                    <option value="teacher">Teacher</option>
                    <option value="moderator">Moderator</option>
                  </select>
                </td>
                <td>
                  <button onClick={submitEdit}>Save</button>
                  <button onClick={() => setEditingUser(null)}>Cancel</button>
                </td>
              </tr>
            ) : (
              <tr key={user.id}>
                <td>{user.id}</td>
                <td>{user.username}</td>
                <td>{user.email}</td>
                <td>{user.role}</td>
                <td>
                  <button onClick={() => deleteUser(user.id)}>Delete</button>
                  <button onClick={() => startEdit(user)}>Edit</button>
                </td>
              </tr>
            )
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ModeratorDashboard;
